  ('galapagos-hammerhead-season', 'galapagos', '10S', '{"liveaboard","ocean"}', '{"activities"}', 'lookahead', 'lookahead', 'Galápagos — schooling hammerheads at their peak', 'The cooler, plankton-rich months bring the big schools of hammerheads to Wolf and Darwin. Seas can be livelier then and the water cooler — a wetsuit and some dive experience help; liveaboards plan around the conditions.', null, null, null, '{"months":[6,7,8,9,10,11]}'::jsonb, 'Jun–Nov (cooler, plankton-rich, big schools)', 'curated', 90, null, null),
