  ('cocos-island-season', 'cocos-island', '10S', '{"liveaboard","ocean"}', '{"activities"}', 'lookahead', 'lookahead', 'Cocos Island (Costa Rica) — pelagic season', 'A legendary big-animal site reached by an open-ocean crossing (~30+ hours) — the passage can be rough and the dives have current, so it suits experienced divers. The reward: schooling hammerheads and big pelagics.', null, null, null, '{"months":[6,7,8,9,10,11]}'::jsonb, 'Jun–Nov (rainier topside, best big-animal action)', 'curated', 70, null, null),
