  ('caribbean-dry-season', 'caribbean', '11C', '{"tropical"}', '{"stay","activities"}', 'lookahead', 'lookahead', 'Caribbean — peak dry-season sunshine', 'The reliable warm-and-clear stretch — gentle trade winds, calm bays, easy swimming and snorkeling. When home is grey and cold, this is the dependable escape.', null, null, null, '{"months":[12,1,2,3,4]}'::jsonb, 'Dec–Apr (dry season; the escape-the-cold window)', 'curated', 90, null, null),
  ('turks-caicos-best', 'turks-caicos', '11C', '{"tropical","liveaboard"}', '{"stay","activities"}', 'lookahead', 'lookahead', 'Turks & Caicos — Grace Bay at its finest', 'Grace Bay at its finest — calm, clear, gentle water over white sand, easy for everyone from toddlers to snorkelers. Best in the dry months; see the honest note on hurricane season for timing. (Our backyard.)', null, null, null, '{"months":[12,1,2,3,4]}'::jsonb, 'Dec–Apr (dry, calm); Atlantic hurricane window Jun–Nov noted', 'curated', 90, null, null),
